/* ── Dark, clean theme ── */

/* System font stack, reset body */
body {
  margin: 0;
  font-family:
    -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Fira Sans',
    'Droid Sans', 'Helvetica Neue', Arial, sans-serif;
  font-size: 14px;
  color: #e6e6e6;
  background: #1e1e1e;
}

/* Subtle accent link – used sparingly */
a {
  color: #6aa6ff;
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}

/* ── Page layout ──
   The app fills the viewport as a column so the embedded host (and therefore
   the scrollable results) gets a definite height in both views. */
html,
body {
  height: 100%;
}
#app {
  height: 100vh;
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 12px;
  box-sizing: border-box;
}

/* ── File-browser widget + hosts ──
   The widget is CHROMELESS: no border, background, or title of its own. It is
   a flex column that fills whichever host renders it (the embedded host or the
   dialog body), keeping the results area scrollable in both contexts. */
.file-browser {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Embedded host: the primary, chromeless surface while the dialog is closed. */
.file-browser-host {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
/* Dialog body slot: the widget is moved here on open. Flexes to fill the
   dialog's remaining height below the titlebar. */
.browser-dialog .dialog-body {
  flex: 1 1 auto;
  min-height: 0;
  display: flex;
  flex-direction: column;
}

/* ── Trigger button (toggle file browser) ── */
.trigger {
  padding: 8px 16px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 14px;
}
.trigger:hover {
  background: #45494d;
}

/* ── Native <dialog> styling ── */
/* Base chrome only (background/border/size/padding). Crucially we do NOT set
   `display` here: a closed <dialog> is hidden by the UA rule
   `dialog:not([open]) { display: none }`, but any author `display` declaration
   overrides the UA sheet entirely and would keep the closed dialog (and thus
   its frame/titlebar) visible on the page. The flex column layout is applied
   ONLY to the open dialog below. */
.browser-dialog {
  background: #252526;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 8px;
  /* Fixed size, clamped so it never overflows small viewports. */
  width: 960px;
  max-width: 94vw;
  height: 640px;
  max-height: 90vh;
  padding: 16px;
  /* Remove default UA margin/padding */
  margin: auto;
  box-sizing: border-box;
}
/* Flex column layout only while open, so the closed dialog stays
   `display: none` (hidden) and renders its frame only when shown. */
.browser-dialog[open] {
  display: flex;
  flex-direction: column;
}
.browser-dialog::backdrop {
  background: rgba(0, 0, 0, 0.6);
}

/* ── Header row ── */
.dialog-header {
  position: relative;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  margin-bottom: 12px;
}
/* Title is absolutely centered across the full dialog width so the close
   button's width never offsets it. pointer-events:none keeps the centered
   text from intercepting clicks meant for the button. */
.dialog-header .title {
  position: absolute;
  left: 0;
  right: 0;
  text-align: center;
  margin: 0;
  font-size: 16px;
  font-weight: 600;
  pointer-events: none;
}
.dialog-header .close-btn {
  position: relative;
  z-index: 1;
  background: none;
  border: none;
  color: #9a9a9a;
  cursor: pointer;
  font-size: 20px;
  line-height: 1;
  padding: 4px 8px;
  border-radius: 4px;
}
.dialog-header .close-btn:hover {
  color: #e6e6e6;
  background: #2d2d30;
}

/* ── Toolbar ── */
.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-bottom: 12px;
}

/* Breadcrumb */
.breadcrumb {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-wrap: wrap;
}
.breadcrumb a {
  color: #9a9a9a;
  font-size: 13px;
}
.breadcrumb a:hover {
  color: #e6e6e6;
  text-decoration: none;
}

/* Search input */
.toolbar input[type='search'],
.toolbar input[type='text'] {
  background: #333337;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
  padding: 6px 10px;
  font-size: 13px;
  outline: none;
  box-sizing: border-box;
  margin-left: auto;
}
.toolbar input[type='search']::placeholder,
.toolbar input[type='text']::placeholder {
  color: #9a9a9a;
}
.toolbar input[type='search']:focus,
.toolbar input[type='text']:focus {
  border-color: #6aa6ff;
}

/* ── Results container (scrollable) ──
   Grows to fill its host's remaining height (flex: 1) and scrolls when the
   table body overflows. `min-height: 0` lets the flex item shrink below its
   content so the scrollbar engages. The table header is made sticky below, so
   only the body rows scroll. */
.results {
  flex: 1;
  min-height: 0;
  overflow: auto;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
}

/* ── Table ── */
.results-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: auto;
}
.results-table th,
.results-table td {
  padding: 6px 8px;
  text-align: left;
  white-space: nowrap;
}
.results-table th {
  color: #9a9a9a;
  font-weight: 500;
  position: sticky;
  top: 0;
  background: #252526;
  z-index: 1;
  border-bottom: 1px solid #3c3c3c;
}
.results-table tbody tr:hover {
  background: #2d2d30;
}

/* ── Small action buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.4;
  white-space: nowrap;
}
.btn:hover {
  background: #45494d;
}
.btn:disabled {
  opacity: 0.5;
  cursor: default;
}
.btn:disabled:hover {
  background: #3a3d41;
}

/* ── Upload control accessibility ──
   The Upload file input is visually hidden with the sr-only clip pattern so it
   stays in the tab order and is keyboard-focusable (WCAG 2.1.1) — using the
   `hidden` attribute (UA display:none) instead would eject it from the focus
   order. The wrapping <label class="btn"> remains the visible affordance; the
   clipped input's own focus outline is invisible, so :focus-within reflects
   focus onto the label for sighted keyboard users. */
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}
.toolbar label.btn:focus-within {
  outline: 2px solid #6aa6ff;
  outline-offset: 2px;
}

/* ── Status footer ── */
.status {
  margin-top: 8px;
  color: #9a9a9a;
  font-size: 12px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(`${this.baseUrl}/browse?path=${encodeURIComponent(path)}`, {
      method: 'GET',
    });
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' },
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData },
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/delete?path=${encodeURIComponent(path)}`, {
      method: 'DELETE',
    });
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/move`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(`${this.baseUrl}/copy`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
    });
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + (await res.text()));
    }
    return (await res.json()) as T;
  }
}

export type View = 'browse' | 'search';

export interface Route {
  view: View;
  path: string;
  query: string;
}

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

/**
 * Parse a full hash (including leading '#') into a Route.
 *
 * Browse format:  #/browse  or  #/browse/<segments>
 * Search format:  #/search?q=<query>&path=<path>
 * Anything else returns the default browse route.
 */
export function parseHash(hash: string): Route {
  if (hash.startsWith('#/browse')) {
    const afterPrefix = hash.slice('#/browse'.length); // everything after "#/browse"
    // Remove the leading '/' if present, then URL-decode what remains
    const path = afterPrefix.startsWith('/')
      ? decodeURIComponent(afterPrefix.slice(1))
      : decodeURIComponent(afterPrefix);
    return { view: 'browse', path, query: '' };
  }

  if (hash.startsWith('#/search')) {
    const queryString = hash.slice('#/search'.length);
    const params = new URLSearchParams(queryString);
    const query = params.get('q') ?? '';
    const path = params.get('path') ?? '';
    return { view: 'search', query, path };
  }

  return DEFAULT_ROUTE;
}

/**
 * Serialize a browse path into a browse hash.
 * Each segment is independently percent-encoded.
 */
export function toBrowseHash(path: string): string {
  if (path === '') {
    return '#/browse';
  }
  const segments = path.split('/');
  const encoded = segments.map((s) => encodeURIComponent(s)).join('/');
  return '#/browse/' + encoded;
}

/**
 * Serialize query and path values into a search hash.
 * Both values are percent-encoded.
 */
export function toSearchHash(query: string, path: string): string {
  return `#/search?q=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`;
}

/**
 * Read the current route from window.location.hash.
 */
export function getCurrentRoute(): Route {
  return parseHash(window.location.hash);
}

/**
 * Subscribe to hash-change events.
 * Returns an unsubscribe function.
 */
export function subscribe(callback: () => void): () => void {
  window.addEventListener('hashchange', callback);
  return () => {
    window.removeEventListener('hashchange', callback);
  };
}

/**
 * Navigate to a given hash (sets window.location.hash).
 */
export function navigate(hash: string): void {
  window.location.hash = hash;
}

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + search <input> + <button> + <label> upload
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, handleUpload } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search, upload
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  const searchBtn = document.createElement('button');
  searchBtn.className = 'btn';
  searchBtn.type = 'button';
  searchBtn.textContent = 'Search';
  const uploadLabel = document.createElement('label');
  uploadLabel.className = 'btn';
  uploadLabel.textContent = 'Upload';
  const uploadInput = document.createElement('input');
  uploadInput.type = 'file';
  uploadInput.multiple = true;
  // Visually hidden via the sr-only clip pattern (the `visually-hidden`
  // class) rather than the `hidden` HTML attribute: the attribute's UA
  // `display:none` ejects the control from the tab order, leaving Upload
  // unreachable via keyboard (WCAG 2.1.1). The class clips it to a 1x1 box
  // so it stays focusable; the visible "Upload" affordance is this wrapping
  // label.btn, and `.toolbar label.btn:focus-within` reflects focus onto it.
  uploadInput.classList.add('visually-hidden');
  // The input is now the element Tab lands on, so it needs its own accessible
  // name (the label text alone doesn't name a focusable input reliably).
  uploadInput.setAttribute('aria-label', 'Upload files');
  uploadLabel.append(uploadInput);
  toolbar.append(breadcrumbEl, searchInput, searchBtn, uploadLabel);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    }
  });

  uploadInput.addEventListener('change', handleUpload);

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
    uploadInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

/**
 * Render a {@link BrowseResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Size | Modified | Actions) with an
 * optional leading ".." parent row.
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { BrowseResult } from '../api.js';
import { formatBytes } from '../format.js';
import { buildTable, makeBrowseRow, makeParentRow, renderBreadcrumb } from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderBrowse(result: BrowseResult): void {
  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  getStatus().textContent =
    result.folderCount +
    ' folders, ' +
    result.fileCount +
    ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', 'Actions']);
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);
}

/**
 * Route dispatcher and rendering-lifecycle owner.
 *
 * `render` reads the current route, fetches the matching result from the API,
 * and delegates to `renderBrowse` / `renderSearch`. It guards against render
 * races (a slower, superseded fetch cannot clobber fresher results) via a
 * monotonic token checked after each `await`.
 *
 * `init` is called once per `startApp` mount: it binds the freshly-built DOM
 * refs into the shared context, registers `render` as the re-render hook (so
 * action buttons and uploads can trigger it without a circular import), tears
 * down any previous mount's hashchange listener, subscribes a new one, and
 * kicks off the initial render.
 */
import { getCurrentRoute, subscribe } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getResults, setRefs, setRenderHook, type DomRefs } from './context.js';
import { renderBrowse } from './render-browse.js';
import { renderSearch } from './render-search.js';

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `init` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/**
 * Bind the freshly-built DOM refs into the shared context, register `render`
 * as the re-render hook, tear down any previous mount's hashchange listener,
 * subscribe a new one, and kick off the initial render.
 */
export function init(refs: DomRefs): void {
  setRefs(refs);
  setRenderHook(render);
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/**
 * Route dispatcher.
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 */
export async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  try {
    if (route.view === 'browse') {
      const result = await getApi().browse(normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderBrowse(result);
    } else {
      const result = await getApi().search(route.query, normalizeRelativePath(route.path));
      if (myToken !== renderToken) return;
      renderSearch(result);
    }
  } catch (err) {
    // A superseded render must not even commit its error.
    if (myToken !== renderToken) return;
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent =
      err instanceof Error ? 'Error: ' + err.message : 'Error: ' + String(err);
  }
}

/**
 * Toolbar event handlers: search submission and file upload.
 *
 * Both operate against the shared DOM/API context (search input value, upload
 * input file list, current route) and trigger a re-render via the context's
 * render hook.
 */
import { getCurrentRoute, navigate, toBrowseHash, toSearchHash } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getSearchInput, getStatus, getUploadInput, rerender } from './context.js';

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * An empty (or whitespace-only) query clears the search instead: it navigates
 * to the browse route for the current path so the server never receives an
 * empty `query`, which it rejects with 400.
 */
export function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = getSearchInput().value.trim();
  if (query === '') {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Upload every selected file to the current path, handle per-file errors, then
 * clear the input, re-render the listing, and surface any failures in the
 * status footer.
 */
export async function handleUpload(): Promise<void> {
  const uploadInput = getUploadInput();
  const list = uploadInput.files;
  const files = list ? Array.from(list) : [];
  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(getCurrentRoute().path);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await getApi().upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  // Clear the input so selecting the same file again re-fires `change`.
  uploadInput.value = '';
  // Re-render the listing first so normal browse/search status is set.
  await rerender();
  // Surface failures after the normal render, so the message is not overwritten.
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    getStatus().textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

/**
 * Tests for `renderBrowse` — the browse-result renderer (table headers, rows,
 * columns, in-app navigation, the Actions column with Download/Delete/Move/Copy
 * + their error surfacing, the breadcrumb, and the status footer).
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded here (carried over from the monolith):
 *  - In-app navigation (directory name links, the ".." parent row, breadcrumb
 *    segments) is verified by asserting on `window.location.hash` after a
 *    click — robust to either a `navigate(...)` call OR an
 *    `<a href="#...">` (happy-dom follows hash-fragment href clicks).
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for browse is
 *    `Name | Size | Modified | Actions`.
 *  - `renderBrowse` operates against the DOM context `startApp` establishes
 *    (module-level element refs), so every test calls `setup()`/`setupCleared()`
 *    first.
 */
import { describe, it, expect, vi } from 'vitest';
import { renderBrowse } from '../app';
import { toBrowseHash } from '../router';
import { formatBytes, normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  setupCleared,
  flush,
  browseResult,
  fileEntry,
  dataRows,
  rowByName,
  cellsOf,
  clickNameLink,
  buttonsByText,
  fetchMock,
  ISO_FMT,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * renderBrowse — table, rows, columns, navigation, actions
 * ========================================================================= */
describe('renderBrowse', () => {
  it('builds a table with header Name | Size | Modified | Actions', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const table = results.querySelector('table');
    expect(table).toBeTruthy();
    const headers = Array.from(table!.querySelectorAll('th')).map((h) => h.textContent!.trim());
    expect(headers).toEqual(['Name', 'Size', 'Modified', 'Actions']);
  });

  it('renders one data row per entry when there is no parent', async () => {
    const entries = [
      fileEntry({ name: 'a.txt', isDirectory: false, size: 10 }),
      fileEntry({ name: 'sub', isDirectory: true }),
    ];
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries }));

    expect(dataRows(results.querySelector('table')!)).toHaveLength(2);
  });

  it('prepends a ".." parent row only when result.parent is not null', async () => {
    const entry = fileEntry({ name: 'a.txt' });
    const { results } = await setupCleared();

    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [entry] }));
    const tableWithParent = results.querySelector('table')!;
    const rowsWithParent = dataRows(tableWithParent);
    expect(rowsWithParent).toHaveLength(2);
    expect(cellsOf(rowsWithParent[0])[0].textContent?.trim()).toBe('..');

    results.innerHTML = '';
    renderBrowse(browseResult({ path: 'docs', parent: null, entries: [entry] }));
    const tableNoParent = results.querySelector('table')!;
    expect(dataRows(tableNoParent)).toHaveLength(1);
    expect(cellsOf(dataRows(tableNoParent)[0])[0].textContent?.trim()).toBe('a.txt');
  });

  it('clicking the ".." row navigates to toBrowseHash(result.parent)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [] }));
    const parentRow = rowByName(results.querySelector('table')!, '..')!;

    clickNameLink(parentRow);

    expect(window.location.hash).toBe(toBrowseHash('docs'));
  });

  describe('directory rows', () => {
    it('renders the name and an em-dash size, and clicking the name navigates into the folder', async () => {
      const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      const row = rowByName(results.querySelector('table')!, 'sub')!;
      const [nameCell, sizeCell] = cellsOf(row);
      expect(nameCell.textContent?.trim()).toBe('sub');
      expect(sizeCell.textContent?.trim()).toBe('—');

      clickNameLink(row);
      expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
    });
  });

  describe('file rows', () => {
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 1536 });

    it('renders the name as plain text (no navigation link)', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const [nameCell] = cellsOf(row);
      expect(nameCell.textContent?.trim()).toBe('a.txt');
      expect(nameCell.querySelector('a, button')).toBeNull();
    });

    it('shows formatBytes(size) for the Size column', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const sizeCell = cellsOf(row)[1];
      expect(sizeCell.textContent?.trim()).toBe(formatBytes(1536));
      expect(sizeCell.textContent?.trim()).toBe('1.5 KB');
    });

    it('shows formatDate(lastModified) for the Modified column', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const modifiedCell = cellsOf(row)[2];
      expect(modifiedCell.textContent?.trim()).toBe(ISO_FMT);
    });

    it('escapes names via textContent (no HTML injection)', async () => {
      const evil = fileEntry({
        name: '<img src=x onerror=alert(1)>',
        path: 'docs/x',
        isDirectory: false,
      });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [evil] }));

      const nameCell = cellsOf(rowByName(results.querySelector('table')!, evil.name)!)[0];
      // The literal markup must NOT have been parsed as HTML.
      expect(results.querySelector('img')).toBeNull();
      expect(nameCell.textContent).toContain('<img');
    });
  });

  describe('Actions column', () => {
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 10 });
    const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });

    function actionsCell(results: HTMLElement, name: string): Element {
      const row = rowByName(results.querySelector('table')!, name)!;
      return cellsOf(row)[3];
    }

    it('gives files a Download anchor pointing at api.downloadUrl(path) with download=name', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));

      const actions = actionsCell(results, 'a.txt');
      const link = actions.querySelector('a.btn') as HTMLAnchorElement;
      expect(link).toBeTruthy();
      expect(link.textContent?.trim()).toBe('Download');
      expect(link.getAttribute('href')).toBe(
        '/api/files/download?path=' + encodeURIComponent('docs/a.txt'),
      );
      expect(link.getAttribute('download')).toBe('a.txt');
    });

    it('gives both files and folders Delete, Move, and Copy buttons', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file, dir] }));

      for (const name of ['a.txt', 'sub']) {
        const actions = actionsCell(results, name);
        expect(buttonsByText(actions, 'Delete')).toHaveLength(1);
        expect(buttonsByText(actions, 'Move')).toHaveLength(1);
        expect(buttonsByText(actions, 'Copy')).toHaveLength(1);
      }
    });

    it('folders have no Download anchor', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));
      const actions = actionsCell(results, 'sub');
      expect(actions.querySelector('a')).toBeNull();
    });

    it('Delete confirms then calls api.delete(entry.path)', async () => {
      const { results } = setup();
      await flush();
      results.innerHTML = '';
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const confirmSpy = vi.spyOn(window, 'confirm').mockReturnValue(true);

      buttonsByText(actionsCell(results, 'a.txt'), 'Delete')[0].click();
      await flush();

      expect(confirmSpy).toHaveBeenCalledWith('Delete "a.txt"?');
      const deleteCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/delete') && (init?.method ?? 'GET') === 'DELETE',
      );
      expect(deleteCalls).toHaveLength(1);
      expect(String(deleteCalls[0][0])).toBe(
        '/api/files/delete?path=' + encodeURIComponent('docs/a.txt'),
      );
    });

    it('Delete does nothing when the user cancels the confirm', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      vi.spyOn(window, 'confirm').mockReturnValue(false);

      buttonsByText(actionsCell(results, 'a.txt'), 'Delete')[0].click();
      await flush();

      expect(fetchMock.mock.calls.some(([u]) => String(u).includes('/delete'))).toBe(false);
    });

    it('Move prompts for a destination then calls api.move with the normalized path', async () => {
      const { results } = setup();
      await flush();
      results.innerHTML = '';
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      vi.spyOn(window, 'prompt').mockReturnValue('/docs/archive/a.txt');

      buttonsByText(actionsCell(results, 'a.txt'), 'Move')[0].click();
      await flush();

      const moveCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/move') && (init?.method ?? 'GET') === 'POST',
      );
      expect(moveCalls).toHaveLength(1);
      const [, init] = moveCalls[0];
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({
        sourcePath: 'docs/a.txt',
        destinationPath: normalizeRelativePath('/docs/archive/a.txt'),
      });
    });

    it('Move does nothing when the user cancels the prompt', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      vi.spyOn(window, 'prompt').mockReturnValue(null);

      buttonsByText(actionsCell(results, 'a.txt'), 'Move')[0].click();
      await flush();

      expect(fetchMock.mock.calls.some(([u]) => String(u).includes('/move'))).toBe(false);
    });

    it('Copy prompts for a destination then calls api.copy with the normalized path', async () => {
      const { results } = setup();
      await flush();
      results.innerHTML = '';
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      vi.spyOn(window, 'prompt').mockReturnValue('/docs/copy/a.txt');

      buttonsByText(actionsCell(results, 'a.txt'), 'Copy')[0].click();
      await flush();

      const copyCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/copy') && (init?.method ?? 'GET') === 'POST',
      );
      expect(copyCalls).toHaveLength(1);
      const [, init] = copyCalls[0];
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({
        sourcePath: 'docs/a.txt',
        destinationPath: normalizeRelativePath('/docs/copy/a.txt'),
      });
    });

    describe('error surfacing (rejecting handlers)', () => {
      /* The Delete/Move/Copy handlers are async and `await api.X(...)`. If the
         API rejects (e.g. 400 for an invalid destination, 500 for a server
         error), `makeActionButton` must surface the error to the user rather
         than leaking an unhandled promise rejection. Contract: the message
         appears in the `.status` footer — the same surface `render()` uses for
         fetch errors — formatted as `Error: <message>`. The ApiClient throws
         `new Error(status + ': ' + body)`, and the wrapper prepends `Error: `,
         so the full text is `Error: <status>: <body>`. The success path is
         unchanged: a handler that resolves normally shows no error. */
      function failMutation(method: string, fragment: string, status: number, text: string): void {
        fetchMock.mockImplementation(async (url, init) => {
          const u = String(url);
          const m = (init?.method ?? 'GET').toUpperCase();
          if (m === method && u.includes(fragment)) {
            return mockResponse({ status, text });
          }
          // Everything else (including any incidental re-render browse) stays
          // permissive so background GETs never throw.
          return mockResponse({ status: 200, body: {} });
        });
      }

      async function actionsForFile(): Promise<{
        actions: Element;
        status: HTMLElement;
        results: HTMLElement;
      }> {
        const ctx = setup();
        await flush();
        ctx.results.innerHTML = '';
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));
        return {
          actions: actionsCell(ctx.results, 'a.txt'),
          status: ctx.status,
          results: ctx.results,
        };
      }

      const browseCallCount = (): number =>
        fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse')).length;

      it('Delete: surfaces a rejecting api.delete in the .status footer', async () => {
        const { actions, status } = await actionsForFile();
        failMutation('DELETE', '/delete', 500, 'boom');
        vi.spyOn(window, 'confirm').mockReturnValue(true);

        buttonsByText(actions, 'Delete')[0].click();
        await flush();

        expect(status.textContent).toBe('Error: 500: boom');
      });

      it('Move: surfaces a rejecting api.move in .status (e.g. 400 invalid destination)', async () => {
        const { actions, status } = await actionsForFile();
        failMutation('POST', '/move', 400, 'invalid destination');
        vi.spyOn(window, 'prompt').mockReturnValue('/docs/missing/a.txt');

        buttonsByText(actions, 'Move')[0].click();
        await flush();

        expect(status.textContent).toBe('Error: 400: invalid destination');
      });

      it('Copy: surfaces a rejecting api.copy in .status', async () => {
        const { actions, status } = await actionsForFile();
        failMutation('POST', '/copy', 409, 'already exists');
        vi.spyOn(window, 'prompt').mockReturnValue('/docs/a.txt');

        buttonsByText(actions, 'Copy')[0].click();
        await flush();

        expect(status.textContent).toBe('Error: 409: already exists');
      });

      it('surfaces a non-Error rejection (e.g. a thrown string) via String(err)', async () => {
        const { actions, status } = await actionsForFile();
        fetchMock.mockImplementation(async (_url, init) => {
          const m = (init?.method ?? 'GET').toUpperCase();
          if (m === 'DELETE') {
            // Reject with a bare string — NOT an Error instance — so the
            // wrapper must fall back to String(err).
            throw 'disk on fire';
          }
          return mockResponse({ status: 200, body: {} });
        });
        vi.spyOn(window, 'confirm').mockReturnValue(true);

        buttonsByText(actions, 'Delete')[0].click();
        await flush();

        expect(status.textContent).toBe('Error: disk on fire');
      });

      it('surfaces the error in .status only — the results table is left intact', async () => {
        const { actions, status, results } = await actionsForFile();
        failMutation('DELETE', '/delete', 500, 'boom');
        vi.spyOn(window, 'confirm').mockReturnValue(true);

        buttonsByText(actions, 'Delete')[0].click();
        await flush();

        // The error is in the status footer, NOT in .results (which is where
        // `render()` surfaces fetch errors — a distinct code path). The table
        // built by renderBrowse is untouched because the handler rejects before
        // calling render().
        expect(status.textContent).toBe('Error: 500: boom');
        expect(results.querySelector('table')).toBeTruthy();
        expect(results.textContent).not.toContain('Error');
        expect(results.textContent).toContain('a.txt');
      });

      it('Delete success: shows no error and still re-renders (success path unchanged)', async () => {
        const { actions, status } = await actionsForFile();
        // Default mock: DELETE returns 200 → handler resolves normally.
        vi.spyOn(window, 'confirm').mockReturnValue(true);
        const before = browseCallCount();

        buttonsByText(actions, 'Delete')[0].click();
        await flush();
        await flush();
        await flush();

        expect(status.textContent).not.toContain('Error');
        // The handler still calls render() on success, so browse is fetched again.
        expect(browseCallCount()).toBeGreaterThan(before);
      });

      it('Move success: shows no error (success path unchanged)', async () => {
        const { actions, status } = await actionsForFile();
        vi.spyOn(window, 'prompt').mockReturnValue('/docs/archive/a.txt');

        buttonsByText(actions, 'Move')[0].click();
        await flush();
        await flush();
        await flush();

        expect(status.textContent).not.toContain('Error');
      });

      it('Copy success: shows no error (success path unchanged)', async () => {
        const { actions, status } = await actionsForFile();
        vi.spyOn(window, 'prompt').mockReturnValue('/docs/archive/a.txt');

        buttonsByText(actions, 'Copy')[0].click();
        await flush();
        await flush();
        await flush();

        expect(status.textContent).not.toContain('Error');
      });

      it('shows no error when the user cancels (confirm false / prompt null)', async () => {
        const { actions, status } = await actionsForFile();

        // Delete cancelled — handler returns early before any await, no throw.
        vi.spyOn(window, 'confirm').mockReturnValue(false);
        buttonsByText(actions, 'Delete')[0].click();
        await flush();
        expect(status.textContent).not.toContain('Error');

        // Move cancelled — prompt returns null, handler returns early.
        vi.spyOn(window, 'prompt').mockReturnValue(null);
        buttonsByText(actions, 'Move')[0].click();
        await flush();
        expect(status.textContent).not.toContain('Error');

        // Copy cancelled — same.
        buttonsByText(actions, 'Copy')[0].click();
        await flush();
        expect(status.textContent).not.toContain('Error');
      });
    });
  });

  describe('breadcrumb', () => {
    function leafByText(container: Element, text: string): Element | undefined {
      return Array.from(container.querySelectorAll('*')).find(
        (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
      );
    }

    it('renders clickable segments that navigate to each cumulative path', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b', entries: [] }));

      const segB = leafByText(breadcrumb, 'b')! as HTMLElement;
      segB.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));

      const segA = leafByText(breadcrumb, 'a')! as HTMLElement;
      segA.click();
      expect(window.location.hash).toBe(toBrowseHash('a'));
    });
  });

  describe('status footer', () => {
    it('shows folder count, file count, and total size for browse results', async () => {
      const { status } = await setupCleared();
      renderBrowse(
        browseResult({
          path: 'docs',
          entries: [],
          folderCount: 2,
          fileCount: 3,
          totalSize: 1536,
        }),
      );

      const text = status.textContent ?? '';
      expect(text).toContain('2 folders');
      expect(text).toContain('3 files');
      expect(text).toContain(formatBytes(1536)); // "1.5 KB"
    });
  });
});

